import { getDefaultClient } from '../../../../client/defaultClient';
import type { Chain } from '../../../chain';
import { getWalletAccounts } from '../../getWalletAccounts';

type GetWalletAccountFromAddressParams = {
  address: string;
  chain: Chain;
};

/**
 * Finds a wallet account by address and blockchain.
 *
 * This function searches through the current session's wallet accounts
 * to find one matching the specified address and chain.
 *
 * @param params.address - The wallet address to search for.
 * @param params.chain - The blockchain the wallet belongs to.
 * @param [client] - The Dynamic client instance. Only required when using multiple Dynamic clients.
 * @returns The matching wallet account, or undefined if not found.
  * @not-instrumented
 */
export const getWalletAccountFromAddress = (
  { address, chain }: GetWalletAccountFromAddressParams,
  client = getDefaultClient()
) => {
  const walletAccounts = getWalletAccounts(client);

  return walletAccounts.find(
    (walletAccount) =>
      walletAccount.address === address && walletAccount.chain === chain
  );
};
