import type { CheckoutTransaction } from '@dynamic-labs/sdk-api-core';

import { getDefaultClient } from '../../../client/defaultClient';
import type { DynamicClient } from '../../../client/types';
import { createCheckoutApiClient } from '../utils/createCheckoutApiClient';

export type BroadcastCheckoutTransactionParams = {
  transactionId: string;
  txHash: string;
};

/**
 * Records the on-chain broadcast of a checkout transaction
 *
 * @param params BroadcastCheckoutTransactionParams - The transaction ID and tx hash.
 * @param [client] - The Dynamic client instance. Only required when using multiple Dynamic clients.
 * @returns The updated checkout transaction
  * @instrumented
 */
export const broadcastCheckoutTransaction = async (
  { transactionId, txHash }: BroadcastCheckoutTransactionParams,
  client: DynamicClient = getDefaultClient()
): Promise<CheckoutTransaction> => {
  const { apiClient, environmentId, sessionToken } =
    await createCheckoutApiClient({ transactionId }, client);

  return apiClient.recordCheckoutBroadcast({
    environmentId,
    recordBroadcastRequest: { txHash },
    transactionId,
    xDynamicCheckoutSessionToken: sessionToken,
  });
};
