import { getCore } from '../../../../client/core/getCore';
import { getDefaultClient } from '../../../../client/defaultClient';
import { createApiClient } from '../../../apiClient';
import { updateAuthFromVerifyResponse } from '../../../auth/updateAuthFromVerifyResponse';
import { setUnverifiedWalletAccounts } from '../../unverifiedWalletAccounts/setUnverifiedWalletAccounts';
import type { WalletAccount } from '../../walletAccount';
import { getPrimaryWalletAccount } from './../getPrimaryWalletAccount';

type SelectPrimaryWalletAccountParams = {
  walletAccount: WalletAccount;
};

/**
 * Make the wallet account provided as the primary wallet account.
  * @instrumented
 */
export const selectPrimaryWalletAccount = async (
  { walletAccount }: SelectPrimaryWalletAccountParams,
  client = getDefaultClient()
): Promise<void> => {
  const core = getCore(client);

  const currentPrimaryWalletAccount = getPrimaryWalletAccount(client);

  if (currentPrimaryWalletAccount?.id === walletAccount.id) {
    return;
  }

  if (walletAccount.verifiedCredentialId) {
    const apiClient = createApiClient({}, client);

    const response = await apiClient.selectUserWallet({
      environmentId: core.environmentId,
      userWalletSelectionRequest: {
        walletId: walletAccount.verifiedCredentialId,
      },
    });

    updateAuthFromVerifyResponse({ response }, client);
  } else {
    const updatedWalletAccount = {
      ...walletAccount,
      lastSelectedAt: new Date(),
    };

    setUnverifiedWalletAccounts(
      {
        unverifiedWalletAccountsToUpdate: [updatedWalletAccount],
      },
      client
    );
  }
};
