import { bufferToHex } from '../../../utils/bufferToHex';
import { compressRawPublicKey } from '../../../utils/compressRawPublicKey';
import type { KeychainService } from '../keychain.types';
import { KeyNotFoundError } from './KeyNotFoundError';
import { deleteIndexedDBItem } from './utils/deleteIndexedDBItem';
import { getIndexedDBItem } from './utils/getIndexedDBItem';
import { openDatabase } from './utils/openDatabase';
import { setIndexedDBItem } from './utils/setIndexedDBItem';

type CreateIndexedDBKeychainServiceParams = {
  dbName?: string;
};

const DEFAULT_DB_NAME = 'dynamic_keychain';

/** @instrumented */
export const createIndexedDBKeychainService = (
  params?: CreateIndexedDBKeychainServiceParams
): KeychainService => {
  const dbName = params?.dbName ?? DEFAULT_DB_NAME;

  const generateKey = async (keyName: string): Promise<string> => {
    const keyPair = await crypto.subtle.generateKey(
      { name: 'ECDSA', namedCurve: 'P-256' },
      false,
      ['sign']
    );

    const rawPublicKey = await crypto.subtle.exportKey(
      'raw',
      keyPair.publicKey
    );

    const compressedPublicKey = compressRawPublicKey(rawPublicKey);
    const publicKeyHex = bufferToHex(compressedPublicKey);

    const db = await openDatabase(dbName);
    await setIndexedDBItem(db, {
      keyName,
      privateKey: keyPair.privateKey,
      publicKeyHex,
    });
    db.close();

    return publicKeyHex;
  };

  const importKey = async (
    keyName: string,
    jwk: JsonWebKey
  ): Promise<string> => {
    const privateKey = await crypto.subtle.importKey(
      'jwk',
      jwk,
      { name: 'ECDSA', namedCurve: 'P-256' },
      false,
      ['sign']
    );

    const publicJwk = { crv: jwk.crv, kty: jwk.kty, x: jwk.x, y: jwk.y };

    const publicCryptoKey = await crypto.subtle.importKey(
      'jwk',
      publicJwk,
      { name: 'ECDSA', namedCurve: 'P-256' },
      true,
      ['verify']
    );

    const rawPublicKey = await crypto.subtle.exportKey('raw', publicCryptoKey);
    const compressedPublicKey = compressRawPublicKey(rawPublicKey);
    const publicKeyHex = bufferToHex(compressedPublicKey);

    const db = await openDatabase(dbName);
    await setIndexedDBItem(db, {
      keyName,
      privateKey,
      publicKeyHex,
    });
    db.close();

    return publicKeyHex;
  };

  const getPublicKey = async (keyName: string): Promise<string | null> => {
    const db = await openDatabase(dbName);
    const entry = await getIndexedDBItem(db, keyName);
    db.close();

    return entry?.publicKeyHex ?? null;
  };

  const sign = async (keyName: string, message: string): Promise<string> => {
    const db = await openDatabase(dbName);
    const entry = await getIndexedDBItem(db, keyName);
    db.close();

    if (!entry) {
      throw new KeyNotFoundError(keyName);
    }

    const encoder = new TextEncoder();
    const data = encoder.encode(message);

    const signature = await crypto.subtle.sign(
      { hash: { name: 'SHA-256' }, name: 'ECDSA' },
      entry.privateKey,
      data
    );

    return bufferToHex(signature);
  };

  const hasKey = async (keyName: string): Promise<boolean> => {
    const db = await openDatabase(dbName);
    const entry = await getIndexedDBItem(db, keyName);
    db.close();

    return entry !== undefined;
  };

  const removeKey = async (keyName: string): Promise<void> => {
    const db = await openDatabase(dbName);
    await deleteIndexedDBItem(db, keyName);
    db.close();
  };

  return {
    generateKey,
    getPublicKey,
    hasKey,
    importKey,
    removeKey,
    sign,
  };
};
