import { getCore } from '../../../client/core/getCore';
import type { DynamicClient } from '../../../client/types';
import type { SessionKeys } from '../sessionKeys.types';

/** @instrumented */
export const generateSessionKeys = async (
  client: DynamicClient
): Promise<SessionKeys> => {
  const core = getCore(client);

  const publicKey = await core.keychain.generateKey('session');

  core.state.set({
    sessionKeys: publicKey,
  });

  return { publicKey };
};
