import { TokenScope } from '@dynamic-labs/sdk-api-core';

import { getCore } from '../../../client/core/getCore';
import { getDefaultClient } from '../../../client/defaultClient';
import { assertDefined } from '../../../utils/assertDefined';
import { getElevatedAccessToken } from '../../auth/getElevatedAccessToken';
import { createApiClient } from '../../apiClient';

type DeleteMfaDeviceParams = {
  deviceId: string;
  mfaAuthToken?: string;
};

/**
 * Deletes a specific MFA device from the user's account.
 *
 * When an elevated access token for `credential:unlink` is available,
 * it is sent via the `x-dyn-elevated-access-token` header and the
 * MFA auth token is not required. Otherwise, `mfaAuthToken` must be
 * provided for backward compatibility with the legacy MFA flow.
 *
 * @param params.deviceId - The unique identifier of the MFA device to delete.
 * @param params.mfaAuthToken - The MFA authentication token. Optional when using elevated access tokens.
 * @param [client] - The Dynamic client instance. Only required when using multiple Dynamic clients.
 * @returns A promise that resolves when the MFA device is successfully deleted.
  * @instrumented
 */
export const deleteMfaDevice = async (
  { deviceId, mfaAuthToken }: DeleteMfaDeviceParams,
  client = getDefaultClient()
) => {
  const core = getCore(client);

  assertDefined(deviceId, 'deviceId is required');

  // Check without consuming — createApiClient handles actual retrieval.
  const hasElevatedToken = getElevatedAccessToken(
    { consume: false, scope: TokenScope.Credentialunlink },
    client
  );

  if (!hasElevatedToken) {
    assertDefined(mfaAuthToken, 'mfaAuthToken is required');
  }

  const apiClient = createApiClient(
    { elevatedAccessTokenScope: TokenScope.Credentialunlink },
    client
  );

  return apiClient.deleteMfaDevice({
    environmentId: core.environmentId,
    mfaDeviceId: deviceId,
    // The generated SDK types xMfaAuthToken as required (string, not string?).
    // When using elevated tokens the backend skips this header entirely, but
    // we still need to satisfy the type. Once the OpenAPI spec marks it optional
    // this fallback can be removed.
    xMfaAuthToken: mfaAuthToken ?? '',
  });
};
