import { getCore } from '../../../../client/core/getCore';
import { getDefaultClient } from '../../../../client/defaultClient';
import { createApiClient } from '../../../apiClient';
import { parseElevatedAccessToken } from '../../updateAuthFromVerifyResponse/elevatedAccessTokens/parseElevatedAccessToken';
import { upsertElevatedAccessToken } from '../../updateAuthFromVerifyResponse/elevatedAccessTokens/upsertElevatedAccessToken';

type RequestExternalAuthElevatedTokenParams = {
  externalJwt: string;
};

/**
 * Requests an elevated access token using an external auth assertion JWT.
 *
 * The assertion JWT must be signed by the customer's backend using the same key
 * registered in the environment's external auth JWKS URL. It must include
 * `sub`, `scope`, `jti`, and `exp` claims.
 *
 * The returned elevated access token is automatically parsed and stored in state,
 * and can be retrieved via `getElevatedAccessToken`.
 *
 * @param params.externalJwt - The assertion JWT signed by the customer's backend.
 * @param [client] - The Dynamic client instance. Only required when using multiple Dynamic clients.
 * @returns A promise that resolves to the assertion response containing the elevated access token.
 * @instrumented
 */
export const requestExternalAuthElevatedToken = async (
  { externalJwt }: RequestExternalAuthElevatedTokenParams,
  client = getDefaultClient()
) => {
  const core = getCore(client);
  const apiClient = createApiClient({}, client);

  const response = await apiClient.externalAuthVerify({
    environmentId: core.environmentId,
    externalAuthSigninRequest: {
      jwt: externalJwt,
    },
  });

  const parsedToken = parseElevatedAccessToken(response.elevatedAccessToken);
  if (parsedToken) {
    const currentTokens = core.state.get().elevatedAccessTokens || [];
    core.state.set({
      elevatedAccessTokens: upsertElevatedAccessToken({
        currentTokens,
        newToken: parsedToken,
      }),
    });
  }

  return response;
};
