import { DEFAULT_PII_FIELDS } from '../constants';
import type {
  Instrumentation,
  InstrumentationConfig,
  InstrumentationEvent,
  InstrumentationTransport,
} from '../instrumentation.types';

type CreateInstrumentationParams = {
  config?: Partial<InstrumentationConfig>;
};

const buildPiiFields = (customFields: string[] = []): string[] => {
  const merged = [...DEFAULT_PII_FIELDS, ...customFields];
  const deduplicated = new Set(merged);
  return [...deduplicated];
};

/**
 * Creates the instrumentation service that gates event emission behind an
 * enabled flag and delegates to a pluggable transport.
 *
 * The transport is intentionally optional at creation time — it is wired in
 * later via setTransport so the SDK can initialise without one. Events logged
 * before a transport is set are simply dropped.
 *
 * Custom piiFields are merged with and deduplicated against the defaults so
 * callers only need to list additional fields, not replicate the baseline.
  * @not-instrumented
 */
export const createInstrumentation = ({
  config: inputConfig,
}: CreateInstrumentationParams = {}): Instrumentation => {
  let transport: InstrumentationTransport | undefined;

  const config: InstrumentationConfig = {
    enabled: inputConfig?.enabled ?? true,
    piiFields: buildPiiFields(inputConfig?.piiFields),
  };

  const emit = (event: InstrumentationEvent) => {
    if (config.enabled) {
      transport?.log(event);
    }
  };

  return {
    config,
    log: emit,
    logFunction: emit,
    setEnabled: (value) => {
      config.enabled = value;
    },
    setTransport: (t) => {
      transport = t;
    },
  };
};
