import { getCore } from '../../../client/core/getCore';
import type { DynamicClient } from '../../../client/types';

type GenerateSessionSignatureParams = {
  sessionId: string;
};

/** @not-instrumented */
export const generateSessionSignature = async (
  { sessionId }: GenerateSessionSignatureParams,
  client: DynamicClient
) => {
  const core = getCore(client);

  const signature = await core.keychain.sign('session', sessionId);

  return { signature };
};
