import type {
  ChainEnum,
  SwapQuoteRequestOrderEnum,
} from '@dynamic-labs/sdk-api-core';

import { getCore } from '../../../client/core/getCore';
import { getDefaultClient } from '../../../client/defaultClient';
import { InvalidParamError } from '../../../errors/InvalidParamError';
import { createApiClient } from '../../apiClient';
import type { Chain } from '../../chain';
import type { SwapQuoteOrder, SwapQuoteResponse } from '../swap.types';

export type GetSwapQuoteParams = {
  from: {
    /* Source wallet address */
    address: string;
    /**
     *  Source token amount, including all decimals (e.g. 1000000 for 1 USDC (6 decimals))
     *  Mutually exclusive with `to.amount`
     */
    amount?: string;
    /* Source chain (e.g. 'EVM', 'SOL', 'SUI') */
    chain: Chain;
    /* Source network id (e.g. 1 for Ethereum, 137 for Polygon) */
    networkId: string;
    /* Source token address. Use zero address for EVM and SOL native tokens. */
    tokenAddress: string;
  };
  /**
   * The price impact threshold above which routes are hidden.
   * As an example, one should specify 0.15 (15%) to hide routes with more than 15% price impact.
   */
  maxPriceImpact?: number;
  /**
   * Which kind of route should be preferred
   *
   * FASTEST: This sorting criterion prioritizes routes with the shortest estimated execution time.
   * Users who value speed and want their transactions to be completed as quickly as possible should choose the fastest routes.
   *
   * CHEAPEST: This criterion focuses on minimizing the cost of the transaction, whether in token amount or USD amount (USD amount minus gas cost).
   * Users looking for the most economical option should choose the cheapest routes.
   *
   */
  order?: SwapQuoteOrder;
  /* The maximum allowed slippage for the transaction as a decimal value. 0.005 represents 0.5%. */
  slippage?: number;
  to: {
    /* Destination wallet address */
    address: string;
    /**
     *  Destination token amount, including all decimals (e.g. 1000000 for 1 USDC (6 decimals))
     *  Mutually exclusive with `from.amount`
     */
    amount?: string;
    /* Destination chain (e.g. 'EVM', 'SOL', 'SUI') */
    chain: Chain;
    /* Destination network id (e.g. 1 for Ethereum, 137 for Polygon) */
    networkId: string;
    /* Destination token address. Use zero address for EVM and SOL native tokens. */
    tokenAddress: string;
  };
};

/**
 * Gets a swap quote
 *
 * @param params GetSwapQuoteParams - The parameters for the swap quote.
 * @param [client] - The Dynamic client instance. Only required when using multiple Dynamic clients.
 * @returns The swap quote details. Use the `signingPayload` field to get the transaction data for the wallet to sign.
 * @instrumented
 */
export const getSwapQuote = async (
  params: GetSwapQuoteParams,
  client = getDefaultClient()
): Promise<SwapQuoteResponse> => {
  const core = getCore(client);
  const apiClient = createApiClient({}, client);

  if (!params.from.amount && !params.to.amount) {
    throw new InvalidParamError('Either from.amount or to.amount is required');
  }

  if (params.from.amount && params.to.amount) {
    throw new InvalidParamError(
      'Only one of from.amount or to.amount is allowed'
    );
  }

  const response = await apiClient.swapQuote({
    environmentId: core.environmentId,
    swapQuoteRequest: {
      from: {
        ...params.from,
        chainId: params.from.networkId,
        // eslint-disable-next-line custom-rules/ban-chain-enum
        chainName: params.from.chain as ChainEnum,
      },
      maxPriceImpact: params.maxPriceImpact,
      order: params.order as SwapQuoteRequestOrderEnum,
      slippage: params.slippage,
      to: {
        ...params.to,
        chainId: params.to.networkId,
        // eslint-disable-next-line custom-rules/ban-chain-enum
        chainName: params.to.chain as ChainEnum,
      },
    },
  });
  return response;
};
