import { getCore } from '../../../client/core/getCore';
import type { DynamicClient } from '../../../client/types';
import { assertDefined } from '../../../utils/assertDefined';
import { getNonce } from '../../../utils/getNonce';
import { generateNonceSignature } from '../generateNonceSignature';
import { generateSessionSignature } from '../generateSessionSignature';

/** @instrumented */
export const getSignedSessionId = async (client: DynamicClient) => {
  const core = getCore(client);

  const sessionId = core.state.get().user?.sessionId;
  assertDefined(sessionId, 'Session ID is required');

  const { signature: signedSessionId } = await generateSessionSignature(
    {
      sessionId,
    },
    client
  );

  assertDefined(signedSessionId, 'Signed session ID is required');

  const nonce = await getNonce(client);

  const { signature: nonceSignature } = await generateNonceSignature(
    {
      nonce,
    },
    client
  );

  assertDefined(nonceSignature, 'Nonce signature is required');

  const signature = `${signedSessionId}/${nonceSignature}/${nonce}`;

  return { signature };
};
