import type {
  ChainEnum,
  SwapStatusRequestChain,
} from '@dynamic-labs/sdk-api-core';

import { getCore } from '../../../client/core/getCore';
import { getDefaultClient } from '../../../client/defaultClient';
import { createApiClient } from '../../apiClient';
import type { Chain } from '../../chain';
import type { SwapStatusResponse } from '../swap.types';

export type GetSwapStatusParams = {
  from?: {
    chain: Chain;
    networkId: string;
  };
  to?: {
    chain: Chain;
    networkId: string;
  };
  txHash: string;
};

/**
 * Gets the status of a swap
 *
 * @param params GetSwapStatusParams - The parameters for the swap status.
 * @param [client] - The Dynamic client instance. Only required when using multiple Dynamic clients.
 * @returns The swap status.
 * @instrumented
 */
export const getSwapStatus = async (
  params: GetSwapStatusParams,
  client = getDefaultClient()
): Promise<SwapStatusResponse> => {
  const core = getCore(client);
  const apiClient = createApiClient({}, client);

  let from: SwapStatusRequestChain | undefined;

  if (params.from) {
    from = {
      chainId: params.from.networkId,
      // eslint-disable-next-line custom-rules/ban-chain-enum
      chainName: params.from.chain as ChainEnum,
    };
  }

  let to: SwapStatusRequestChain | undefined;
  if (params.to) {
    to = {
      chainId: params.to.networkId,
      // eslint-disable-next-line custom-rules/ban-chain-enum
      chainName: params.to.chain as ChainEnum,
    };
  }

  const response = await apiClient.swapStatus({
    environmentId: core.environmentId,
    swapStatusRequest: {
      from,
      to,
      txHash: params.txHash,
    },
  });

  return {
    status: response.status,
    substatus: response.substatus,
  };
};
