/* eslint-disable no-restricted-globals */

/**
 * Retrieves all providers from a window path.
 *
 * Unlike getInjectedProviderFromWindow which returns only the first provider,
 * this function returns ALL providers found at the path, including those
 * in a .providers array if present.
 *
 * This is particularly useful for detecting wallet providers in wallet app
 * in-app browsers, where wallets inject their provider into the window object.
 *
 * @param path - Dot-separated path to traverse (e.g., "ethereum")
 * @returns Array of all providers found, or empty array if none
  * @not-instrumented
 */
export const getAllProvidersFromWindow = <T = unknown>(path: string): T[] => {
  if (typeof window === 'undefined') {
    return [];
  }

  // Traverse the path safely
  const target: unknown = path.split('.').reduce<unknown>(
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (acc, key) => (acc == null ? null : (acc as any)[key]),
    window
  );

  if (typeof target !== 'object' || target === null) {
    return [];
  }

  if (Array.isArray(target)) {
    return target as T[];
  }

  const providers: T[] = [];

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const providersArray = (target as any).providers;

  // If target has a .providers array, return all providers from it
  if (providersArray && Array.isArray(providersArray)) {
    providers.push(...(providersArray as T[]));
  }

  // Always include the target itself as a provider (if it's not just a container)
  // This handles the case where window.ethereum is both a provider AND has a providers array
  providers.push(target as T);

  return providers;
};
