import { getCore } from '../../../client/core/getCore';
import type { DynamicClient } from '../../../client/types';
import { assertDefined } from '../../../utils/assertDefined';

type GenerateNonceSignatureParams = {
  nonce: string;
};

/** @not-instrumented */
export const generateNonceSignature = async (
  { nonce }: GenerateNonceSignatureParams,
  client: DynamicClient
) => {
  const core = getCore(client);

  assertDefined(core.keychain, 'Keychain service not available');

  const signature = await core.keychain.sign('session', nonce);

  return { signature };
};
