import { getDefaultClient } from '../../../../client/defaultClient';
import { getWalletProviderFromWalletAccount } from '../../utils/getWalletProviderFromWalletAccount';
import type { WalletAccount } from '../../walletAccount';

type GetActiveNetworkIdParams = {
  walletAccount: WalletAccount;
};

/**
 * This function returns the network identifier that this wallet account's provider is currently connected to.
 *
 * @param params.walletAccount - The wallet account to get the network ID for.
 * @param [client] - The Dynamic client instance. Only required when using multiple Dynamic clients.
 * @returns A promise that resolves to the active network ID for the wallet account.
  * @instrumented
 */
export const getActiveNetworkId = (
  { walletAccount }: GetActiveNetworkIdParams,
  client = getDefaultClient()
) => {
  const walletProvider = getWalletProviderFromWalletAccount(
    { walletAccount },
    client
  );

  return walletProvider.getActiveNetworkId();
};
