import { getDefaultClient } from '../../../../../client/defaultClient';
import { getWalletProviderByKey } from '../../../getWalletProviderByKey';
import { assertWalletProviderMethodDefined } from '../../../utils/assertWalletProviderMethodDefined';
import type { WalletProviderEvents } from '../walletProviderEvents.types';

type OffWalletProviderEventParams<
  E extends Extract<keyof WalletProviderEvents, string>
> = {
  callback: WalletProviderEvents[E];
  event: E;
  walletProviderKey: string;
};

/**
 * Removes a listener from a wallet provider event.
 * You can alternatively use the returned function from `onWalletProviderEvent` instead of using this function.
 *
 * @param params.callback - The callback function to remove. This should be the same function that was passed to the `onWalletProviderEvent` function.
 * @see onWalletProviderEvent
 * @param params.event - The event name to remove the listener from.
 * @param params.walletProviderKey - The unique key identifying the wallet provider to remove the listener from.
 * @param [client] - The Dynamic client instance. Only required when using multiple Dynamic clients.
  * @instrumented
 */
export const offWalletProviderEvent = <
  E extends Extract<keyof WalletProviderEvents, string>
>(
  { callback, event, walletProviderKey }: OffWalletProviderEventParams<E>,
  client = getDefaultClient()
) => {
  const walletProvider = getWalletProviderByKey({ walletProviderKey }, client);

  assertWalletProviderMethodDefined(walletProvider, 'events');

  // We use any here because typescript is messing up the type inference
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  walletProvider.events.off(event, callback as any);
};
