import type { SDKApi } from '@dynamic-labs/sdk-api-core';

import { getCore } from '../../../../client/core/getCore';
import type { DynamicClient } from '../../../../client/types';
import { CheckoutSessionTokenMissingError } from '../../../../errors/CheckoutSessionTokenMissingError';
import { createApiClient } from '../../../apiClient';
import { createCheckoutSessionTokenStorageKey } from '../createCheckoutSessionTokenStorageKey';

type CreateCheckoutApiClientParams = {
  transactionId: string;
};

type CheckoutApiClientResult = {
  apiClient: SDKApi;
  environmentId: string;
  sessionToken: string;
};

/** @not-instrumented */
export const createCheckoutApiClient = async (
  { transactionId }: CreateCheckoutApiClientParams,
  client: DynamicClient
): Promise<CheckoutApiClientResult> => {
  const core = getCore(client);
  const apiClient = createApiClient({}, client);

  const sessionToken = await core.storage.getItem(
    createCheckoutSessionTokenStorageKey(transactionId)
  );

  if (!sessionToken) {
    throw new CheckoutSessionTokenMissingError({ transactionId });
  }

  return {
    apiClient,
    environmentId: core.environmentId,
    sessionToken,
  };
};
