import { getCore } from '../../../client/core/getCore';
import { getDefaultClient } from '../../../client/defaultClient';
import type { DynamicClient } from '../../../client/types';
import { assertDefined } from '../../../utils/assertDefined';
import { createApiClient } from '../../apiClient';
import type { CheckoutTransactionCreateResponse } from '../checkout.types';
import { getCheckouts } from '../getCheckouts';
import { createCheckoutSessionTokenStorageKey } from '../utils/createCheckoutSessionTokenStorageKey';

export type CreateCheckoutTransactionParams = {
  amount: string;
  checkoutId?: string;
  currency: string;
  expiresIn?: number;
  memo?: object;
};

/**
 * Creates a new checkout transaction and stores the session token for subsequent calls
 *
 * @param params CreateCheckoutTransactionParams - The parameters for the checkout transaction.
 * @param [client] - The Dynamic client instance. Only required when using multiple Dynamic clients.
 * @returns The created transaction with session token
 * @instrumented
 */
export const createCheckoutTransaction = async (
  params: CreateCheckoutTransactionParams,
  client: DynamicClient = getDefaultClient()
): Promise<CheckoutTransactionCreateResponse> => {
  const core = getCore(client);
  const apiClient = createApiClient({}, client);

  const checkouts = await getCheckouts(client);

  // If no checkout ID is provided, try to fallback to the first checkout in the list
  const checkoutId = params.checkoutId || checkouts?.[0]?.id;

  assertDefined(
    checkoutId,
    'No checkout found. Please make sure you have a Checkout setup in the Dashboard.'
  );

  const result = await apiClient.createCheckoutTransaction({
    checkoutId,
    checkoutTransactionCreateRequest: {
      amount: params.amount,
      currency: params.currency,
      expiresIn: params.expiresIn,
      memo: params.memo,
    },
    environmentId: core.environmentId,
  });

  await core.storage.setItem(
    createCheckoutSessionTokenStorageKey(result.transaction.id),
    result.sessionToken
  );

  return result;
};
