import type { Checkout } from '@dynamic-labs/sdk-api-core';

import type { DynamicClient } from '../../../client/types';
import { assertDefined } from '../../../utils/assertDefined';

/** @not-instrumented */
export const getCheckouts = async (
  client: DynamicClient
): Promise<Checkout[]> => {
  const projectSettings = client.projectSettings;

  assertDefined(projectSettings, 'Project settings are not available');

  return projectSettings.checkouts ?? [];
};
