import { getDefaultClient } from '../../../../client/defaultClient';
import { NetworkAddingUnavailableError } from '../../../../errors/NetworkAddingUnavailableError';
import { getWalletProviderByKey } from '../../getWalletProviderByKey';
import type { WalletAccount } from '../../walletAccount';
import type { NetworkData } from '../networkProvider/networkProvider.types';

type AddNetworkParams = {
  networkData: NetworkData;
  walletAccount: WalletAccount;
};

/**
 * Adds a network to the wallet provider.
 *
 * This function requests that the wallet provider add a network
 * to its list of available networks.
 *
 * @param params.networkData - The network configuration data to add to the wallet.
 * @param params.walletAccount - The wallet account to add the network for.
 * @param [client] - The Dynamic client instance. Only required when using multiple Dynamic clients.
 * @returns A promise that resolves when the network addition is complete.
 * @throws NetworkAddingUnavailableError If the wallet provider doesn't support adding networks.
  * @instrumented
 */
export const addNetwork = async (
  { networkData, walletAccount }: AddNetworkParams,
  client = getDefaultClient()
) => {
  const walletProvider = getWalletProviderByKey(
    { walletProviderKey: walletAccount.walletProviderKey },
    client
  );

  if (walletProvider.addNetwork === undefined) {
    throw new NetworkAddingUnavailableError({
      extraMessages: [
        `Wallet provider ${walletAccount.walletProviderKey} does not have addNetwork method`,
      ],
      originalError: null,
      walletProviderKey: walletAccount.walletProviderKey,
    });
  }

  return walletProvider.addNetwork({ networkData });
};
