import type { InboundMessage, RealtimeChannel, messageCallback } from 'ably';
import type { BaseRealtime } from 'ably/modular';
import EventEmitter from 'eventemitter3';

import { getCore } from '../../../client/core/getCore';
import { InvalidRealtimePublishError } from '../../../errors/InvalidRealtimePublishError';
import { RealtimeNotConnectedError } from '../../../errors/RealtimeNotConnectedError';
import { createApiClient } from '../../../modules/apiClient';
import { isServerSideRendering } from '../../../utils/isServerSideRendering';
import type {
  RealtimeChannelSchema,
  RealtimeConnectionState,
  RealtimeEventMap,
  RealtimeService,
} from '../realtime.types';

const ABLY_STATE_TO_REALTIME_STATE: Record<string, RealtimeConnectionState> = {
  closed: 'closed',
  closing: 'closing',
  connected: 'connected',
  connecting: 'connecting',
  disconnected: 'disconnected',
  failed: 'failed',
  initialized: 'idle',
  suspended: 'suspended',
};

const mapAblyState = (ablyState: string): RealtimeConnectionState =>
  ABLY_STATE_TO_REALTIME_STATE[ablyState] ?? 'idle';

/**
 * Creates a realtime pub/sub service backed by Ably.
 *
 * The service starts idle. Call `connect({ client })` to establish
 * a connection, passing the DynamicClient explicitly.
 *
 * SSR environments receive a no-op implementation.
  * @instrumented
 */
export const createRealtimeService = (): RealtimeService => {
  if (isServerSideRendering()) {
    return {
      connect: () => Promise.resolve(),
      disconnect: () => {},
      getConnectionState: () => 'idle',
      off: () => {},
      on: () => {},
      publish: () => Promise.resolve(),
      subscribe: () => Promise.resolve(),
      unsubscribe: () => {},
    };
  }

  const eventEmitter = new EventEmitter<RealtimeEventMap>();
  const channels = new Map<string, RealtimeChannel>();
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const handlerMap = new WeakMap<(message: { data: any }) => void, messageCallback<InboundMessage>>();

  let ablyClient: BaseRealtime | undefined;
  let connectionState: RealtimeConnectionState = 'idle';
  let isConnecting = false;

  const setConnectionState = (state: RealtimeConnectionState) => {
    connectionState = state;
    eventEmitter.emit('connectionStateChange', state);
  };

  const getOrCreateChannel = (channelName: string): RealtimeChannel => {
    const existing = channels.get(channelName);

    if (existing) {
      return existing;
    }

    if (!ablyClient) {
      throw new RealtimeNotConnectedError();
    }

    const channel = ablyClient.channels.get(channelName);
    channels.set(channelName, channel);

    return channel;
  };

  const connect: RealtimeService['connect'] = async ({ client }) => {
    if (isConnecting) {
      return;
    }

    isConnecting = true;

    try {
      const core = getCore(client);

      if (ablyClient) {
        ablyClient.close();
        channels.clear();
      }

      // Dynamic import to keep the module tree-shakeable
      // and avoid loading Ably in SSR environments
      const {
        BaseRealtime: AblyBaseRealtime,
        FetchRequest,
        WebSocketTransport,
      } = await import('ably/modular');

      ablyClient = new AblyBaseRealtime({
        // authCallback must return void (not Promise<void>), so we use
        // .then().catch() instead of async/await to avoid returning a Promise
        // to Ably's callback-style auth handler.
        authCallback: (_tokenParams, callback) => {
          const apiClient = createApiClient({}, client);

          apiClient
            .getRealtimeAuthToken({ environmentId: core.environmentId })
            .then((response) => {
              callback(null, response.token);
            })
            .catch((err: unknown) => {
              const message = err instanceof Error ? err.message : String(err);
              callback(message, null);
            });
        },
        autoConnect: false,
        plugins: { FetchRequest, WebSocketTransport },
      });

      ablyClient.connection.on((stateChange) => {
        setConnectionState(mapAblyState(stateChange.current));
      });

      ablyClient.connect();
    } finally {
      isConnecting = false;
    }
  };

  const disconnect: RealtimeService['disconnect'] = () => {
    if (!ablyClient) {
      return;
    }

    for (const channel of channels.values()) {
      channel.detach().catch(() => {});
    }

    channels.clear();
    ablyClient.close();
    ablyClient = undefined;
  };

  const subscribe: RealtimeService['subscribe'] = async <T>({
    channelSchema,
    callback,
  }: {
    callback: (message: { data: T }) => void;
    channelSchema: RealtimeChannelSchema<T>;
  }) => {
    const channel = getOrCreateChannel(channelSchema.channel);

    const handler: messageCallback<InboundMessage> = (message) => {
      const parsed = channelSchema.schema.safeParse(message.data);

      if (!parsed.success) {
        return;
      }

      callback({ data: parsed.data });
    };

    handlerMap.set(callback, handler);

    await channel.subscribe(handler);
  };

  const unsubscribe: RealtimeService['unsubscribe'] = <T>({
    channelSchema,
    callback,
  }: {
    callback: (message: { data: T }) => void;
    channelSchema: RealtimeChannelSchema<T>;
  }) => {
    const channel = channels.get(channelSchema.channel);

    if (!channel) {
      return;
    }

    const handler = handlerMap.get(callback);

    if (handler) {
      channel.unsubscribe(handler);
      handlerMap.delete(callback);
    }
  };

  const publish: RealtimeService['publish'] = async <T>({
    channelSchema,
    data,
  }: {
    channelSchema: RealtimeChannelSchema<T>;
    data: T;
  }) => {
    const parsed = channelSchema.schema.safeParse(data);

    if (!parsed.success) {
      throw new InvalidRealtimePublishError({ channel: channelSchema.channel });
    }

    const channel = getOrCreateChannel(channelSchema.channel);
    await channel.publish('message', parsed.data);
  };

  return {
    connect,
    disconnect,
    getConnectionState: () => connectionState,
    off: (event, callback) => {
      eventEmitter.off(event, callback);
    },
    on: (event, callback) => {
      eventEmitter.on(event, callback);
    },
    publish,
    subscribe,
    unsubscribe,
  };
};
