import type { Logger } from '../../logger/logger.types';
import { getUserAgent } from '../../../utils/getUserAgent/getUserAgent';
import type { ObservableState } from '../../../utils/observable/observable.types';
import { extractSessionId } from '../../../modules/auth/extractSessionId/extractSessionId';
import type { Instrumentation } from '../instrumentation.types';

type ConnectLoggerToInstrumentationParams = {
  environmentId: string;
  instrumentation: Instrumentation;
  logger: Logger;
  sdkSessionId: string;
  sdkVersion: string;
  state: ObservableState<DynamicCoreState>;
};

/**
 * Subscribes to the logger's 'log' event and forwards every entry to the
 * instrumentation service as an InstrumentationEvent.
 *
 * Bridges the logger and instrumentation subsystems without coupling them
 * at construction time — either can exist without the other.
 * Only error-level log entries are forwarded.
  * @not-instrumented
 */
export const connectLoggerToInstrumentation = ({
  environmentId,
  instrumentation,
  logger,
  sdkSessionId,
  sdkVersion,
  state,
}: ConnectLoggerToInstrumentationParams) => {
  logger.on('log', (level, message, ...args) => {
    if (level !== 'error') {
      return;
    }

    const { token, user } = state.get();

    instrumentation.log({
      environmentId,
      parameters: { args, message },
      sdkSessionId,
      sdkVersion,
      timestamp: new Date().toISOString(),
      tokenSessionId: token ? extractSessionId(token) : null,
      userAgent: getUserAgent(),
      userId: user?.id ?? null,
    });
  });
};
