import type { Fetch } from '../../../fetch';
import type {
  InstrumentationEvent,
  InstrumentationTransport,
} from '../../instrumentation.types';

const LOGS_BASE_URL = 'https://logs.dynamicauth.com/api/v1';

type CreateDynamicTransportParams = {
  environmentId: string;
  fetch: Fetch;
};

/**
 * Creates a batched transport that ships instrumentation events to Dynamic's
 * log ingestion endpoint.
 *
 * Events are queued synchronously and flushed as a single HTTP batch in the
 * next microtask (via queueMicrotask). Multiple log() calls within the same
 * synchronous tick are coalesced into one request, avoiding a round-trip per
 * event.
 *
 * Fetch errors are swallowed to prevent an instrumentation failure from
 * triggering another instrumentation event and causing an infinite loop.
 *
 * Works in both browser and SSR environments — fetch is injected and
 * queueMicrotask is available in Node.js >= 11.
  * @not-instrumented
 */
export const createDynamicTransport = (
  params: CreateDynamicTransportParams
): InstrumentationTransport => {
  const queue: InstrumentationEvent[] = [];
  let flushScheduled = false;

  const flush = () => {
    flushScheduled = false;
    // splice(0) atomically drains the queue and returns all accumulated events.
    // Using splice rather than reassigning the array reference ensures events
    // logged between flush scheduling and flush execution are not silently dropped.
    const events = queue.splice(0);

    if (events.length === 0) return;

    void params
      .fetch(`${LOGS_BASE_URL}/${params.environmentId}`, {
        body: JSON.stringify(events),
        headers: { 'Content-Type': 'application/json' },
        method: 'POST',
      })
      .catch(() => {
        // swallow errors to prevent infinite logging loops
      });
  };

  return {
    log: (event) => {
      queue.push(event);

      if (!flushScheduled) {
        flushScheduled = true;
        queueMicrotask(flush);
      }
    },
  };
};
