import { getCore } from '../../../client/core/getCore';
import { getDefaultClient } from '../../../client/defaultClient';
import type { CheckoutTransaction } from '../checkout.types';
import { createCheckoutApiClient } from '../utils/createCheckoutApiClient';
import { createCheckoutSessionTokenStorageKey } from '../utils/createCheckoutSessionTokenStorageKey';

export type CancelCheckoutTransactionParams = {
  transactionId: string;
};

/**
 * Cancels a checkout transaction before it has been broadcasted
 *
 * @param params CancelCheckoutTransactionParams - The transaction to cancel.
 * @param [client] - The Dynamic client instance. Only required when using multiple Dynamic clients.
 * @returns The cancelled checkout transaction
  * @instrumented
 */
export const cancelCheckoutTransaction = async (
  { transactionId }: CancelCheckoutTransactionParams,
  client = getDefaultClient()
): Promise<CheckoutTransaction> => {
  const { apiClient, environmentId, sessionToken } =
    await createCheckoutApiClient({ transactionId }, client);

  const result = await apiClient.cancelCheckoutTransaction({
    environmentId,
    transactionId,
    xDynamicCheckoutSessionToken: sessionToken,
  });

  const core = getCore(client);
  await core.storage.removeItem(
    createCheckoutSessionTokenStorageKey(transactionId)
  );

  return result;
};
