import { getDefaultClient } from '../../../client/defaultClient';
import type { CheckoutTransaction } from '../checkout.types';
import { createCheckoutApiClient } from '../utils/createCheckoutApiClient';

export type GetCheckoutTransactionQuoteParams = {
  fromTokenAddress: string;
  slippage?: number;
  transactionId: string;
};

/**
 * Fetches a quote for a checkout transaction
 *
 * @param params GetCheckoutTransactionQuoteParams - The quote parameters.
 * @param [client] - The Dynamic client instance. Only required when using multiple Dynamic clients.
 * @returns The updated checkout transaction with quote data
  * @instrumented
 */
export const getCheckoutTransactionQuote = async (
  {
    fromTokenAddress,
    slippage,
    transactionId,
  }: GetCheckoutTransactionQuoteParams,
  client = getDefaultClient()
): Promise<CheckoutTransaction> => {
  const { apiClient, environmentId, sessionToken } =
    await createCheckoutApiClient({ transactionId }, client);

  return apiClient.quoteCheckoutTransaction({
    environmentId,
    quoteRequest: {
      fromTokenAddress,
      slippage,
    },
    transactionId,
    xDynamicCheckoutSessionToken: sessionToken,
  });
};
