import type {
  ChainEnum,
  CheckoutSourceTypeEnum,
} from '@dynamic-labs/sdk-api-core';

import { getDefaultClient } from '../../../client/defaultClient';
import type { Chain } from '../../chain';
import type { CheckoutTransaction } from '../checkout.types';
import { createCheckoutApiClient } from '../utils/createCheckoutApiClient';

export type AttachCheckoutTransactionSourceParams = {
  fromAddress: string;
  fromChainId: string;
  fromChainName: Chain;
  transactionId: string;
};

/**
 * Attaches a wallet source to a checkout transaction
 *
 * @param params AttachCheckoutTransactionSourceParams - The source details to attach.
 * @param [client] - The Dynamic client instance. Only required when using multiple Dynamic clients.
 * @returns The updated checkout transaction
  * @instrumented
 */
export const attachCheckoutTransactionSource = async (
  {
    fromAddress,
    fromChainId,
    fromChainName,
    transactionId,
  }: AttachCheckoutTransactionSourceParams,
  client = getDefaultClient()
): Promise<CheckoutTransaction> => {
  const { apiClient, environmentId, sessionToken } =
    await createCheckoutApiClient({ transactionId }, client);

  return apiClient.attachSource({
    attachSourceRequest: {
      fromAddress,
      fromChainId,
      // eslint-disable-next-line custom-rules/ban-chain-enum
      fromChainName: fromChainName as ChainEnum,
      // TODO: This should come from the params - update once we have more clarity on how to handle other types
      sourceType: 'wallet' as CheckoutSourceTypeEnum,
    },
    environmentId,
    transactionId,
    xDynamicCheckoutSessionToken: sessionToken,
  });
};
