import type { ChainEnum, TokenBalance } from '@dynamic-labs/sdk-api-core';

import { getCore } from '../../../client/core/getCore';
import { getDefaultClient } from '../../../client/defaultClient';
import { createApiClient } from '../../apiClient';
import { getWalletProviderFromWalletAccount } from '../../wallets/utils/getWalletProviderFromWalletAccount';
import type { WalletAccount } from '../../wallets/walletAccount';

export type GetBalancesParams = {
  /**
   * Whether to filter out spam tokens.
   * Defaults to true.
    * @instrumented
 */
  filterSpamTokens?: boolean;
  /** Whether to force a refresh of the balances instead of using the api cached value. */
  forceRefresh?: boolean;
  /** Whether to include the native token balance. */
  includeNative?: boolean;
  /** Whether to include the prices of the tokens. */
  includePrices?: boolean;
  /**
   * The network ID to get the balances for.
   * If not provided, the active network ID will be used.
   */
  networkId?: number;
  /** The wallet account to get the balances for. */
  walletAccount: WalletAccount;
  /** If provided, only return balances for the specified contracts. */
  whitelistedContracts?: Array<string>;
};

/**
 * Retrieves the token balances for a wallet account.
 *
 * This function fetches the balances of the tokens for the specified wallet account.
 *
 * @param params.walletAccount - The wallet account to get the balances for.
 * @param [client] - The Dynamic client instance. Only required when using multiple Dynamic clients.
 * @returns A promise that resolves to an array of token balances.
  * @not-instrumented
 */
export const getBalances = async (
  {
    walletAccount,
    networkId,
    includePrices,
    includeNative,
    filterSpamTokens,
    whitelistedContracts,
    forceRefresh,
  }: GetBalancesParams,
  client = getDefaultClient()
): Promise<TokenBalance[]> => {
  const core = getCore(client);
  const apiClient = createApiClient({}, client);

  if (!networkId) {
    const walletProvider = getWalletProviderFromWalletAccount(
      {
        walletAccount,
      },
      client
    );
    const activeNetworkId = await walletProvider.getActiveNetworkId();
    networkId = Number(activeNetworkId.networkId);
  }

  const balances = await apiClient.getAccountBalances({
    accountAddress: walletAccount.address,
    // eslint-disable-next-line custom-rules/ban-chain-enum
    chainName: walletAccount.chain as ChainEnum,
    environmentId: core.environmentId,
    filterSpamTokens,
    forceRefresh,
    includeNative,
    includePrices,
    networkId,
    whitelistedContracts,
  });

  return balances;
};
