import { getDefaultClient } from '../../../client/defaultClient';
import { assertDefined } from '../../../utils/assertDefined';
import { executeSwapTransaction } from '../../swap/executeSwapTransaction';
import type { WalletAccount } from '../../wallets/walletAccount';
import { broadcastCheckoutTransaction } from '../broadcastCheckoutTransaction';
import type { CheckoutTransaction } from '../checkout.types';
import { prepareCheckoutTransaction } from '../prepareCheckoutTransaction';

export type SubmitCheckoutTransactionParams = {
  onStepChange?: (step: 'approval' | 'transaction') => void;
  transactionId: string;
  walletAccount: WalletAccount;
};

/**
 * Prepares, signs, and broadcasts a checkout transaction in one call.
 *
 * Orchestrates the full submission flow:
 * 1. Calls prepareCheckoutTransaction to advance to signing state and lock the quote
 * 2. Ensures the wallet is on the correct network for the transaction
 * 3. Delegates on-chain signing to the wallet provider's executeSwapTransaction method
 * 4. Calls broadcastCheckoutTransaction with the resulting txHash
 *
 * @param params SubmitCheckoutTransactionParams - The transaction ID, wallet account, and optional step callback.
 * @param [client] - The Dynamic client instance. Only required when using multiple Dynamic clients.
 * @returns The broadcasted checkout transaction
 * @instrumented
 */
export const submitCheckoutTransaction = async (
  {
    onStepChange,
    transactionId,
    walletAccount,
  }: SubmitCheckoutTransactionParams,
  client = getDefaultClient()
): Promise<CheckoutTransaction> => {
  const prepared = await prepareCheckoutTransaction({ transactionId }, client);

  assertDefined(
    prepared.signingPayload,
    'No signing payload returned from prepare — quote may be missing transaction data'
  );

  const { transactionHash } = await executeSwapTransaction({
    onStepChange,
    signingPayload: prepared.signingPayload,
    walletAccount,
  });

  return broadcastCheckoutTransaction(
    { transactionId, txHash: transactionHash },
    client
  );
};
