import { getDefaultClient } from '../../../client/defaultClient';
import { InvalidParamError } from '../../../errors/InvalidParamError';
import { assertWalletProviderMethodDefined } from '../../wallets/utils/assertWalletProviderMethodDefined';
import { getWalletProviderFromWalletAccount } from '../../wallets/utils/getWalletProviderFromWalletAccount';
import type { WalletAccount } from '../../wallets/walletAccount';
import { SWAP_SUPPORTED_CHAINS } from '../constants';
import type { SwapTransactionSigningPayload } from '../swap.types';

export type ExecuteSwapTransactionParams = {
  /**
   * The callback to invoke when the transaction execution step changes.
   *
   * 'approval' - The approval step begins. (only happens for ERC-20 tokens when the allowance is insufficient)
   * 'transaction' - The transaction step begins.
   */
  onStepChange?: (step: 'approval' | 'transaction') => void;
  /**
   * The signing payload for the swap transaction.
   * Usually obtained from a `getSwapQuote` call.
   */
  signingPayload: SwapTransactionSigningPayload;
  /**
   * The wallet account to execute the swap transaction on.
   */
  walletAccount: WalletAccount;
};

/**
 * Executes a swap transaction
 *
 * @param params ExecuteSwapTransactionParams - The parameters for the swap transaction.
 * @param [client] - The Dynamic client instance. Only required when using multiple Dynamic clients.
 * @returns The transaction hash.
 * @instrumented
 */
export const executeSwapTransaction = async (
  { walletAccount, signingPayload, onStepChange }: ExecuteSwapTransactionParams,
  client = getDefaultClient()
): Promise<{ transactionHash: string }> => {
  if (!SWAP_SUPPORTED_CHAINS.includes(walletAccount.chain)) {
    throw new InvalidParamError(
      `Chain ${walletAccount.chain} is not supported for swap transactions`
    );
  }

  const walletProvider = getWalletProviderFromWalletAccount(
    { walletAccount },
    client
  );

  assertWalletProviderMethodDefined(walletProvider, 'executeSwapTransaction');

  const requiredNetworkId = signingPayload.chainId;

  if (requiredNetworkId && walletProvider.switchActiveNetwork) {
    const { networkId: activeNetworkId } =
      await walletProvider.getActiveNetworkId();

    if (activeNetworkId !== requiredNetworkId) {
      await walletProvider.switchActiveNetwork({
        networkId: requiredNetworkId,
      });
    }
  }

  const { transactionHash } = await walletProvider.executeSwapTransaction({
    onStepChange,
    signingPayload,
    walletAccount,
  });

  return { transactionHash };
};
